function getModelInfo() {
return {
  'gpt-image-2': {
    badge: T.model_badge, badgeColor: '#7c3aed',
    description: T.model_desc,
    strengths: [T.strength_1, T.strength_2, T.strength_3, T.strength_4, T.strength_5],
    qualities: [['low', T.quality_low], ['medium', T.quality_medium], ['high', T.quality_high]],
    defaultQuality: 'medium',
    sizes: [
      ['1024x1024', '1024×1024 — ' + T.size_square],
      ['1536x1024', '1536×1024 — ' + T.size_landscape],
      ['1024x1536', '1024×1536 — ' + T.size_portrait],
      ['auto', T.size_auto],
    ],
    defaultSize: '1536x1024',
    tip: T.model_tip,
    gradient: 'linear-gradient(135deg,#7c3aed,#4f46e5)',
    tipBg: '#f5f3ff', tipBorder: '#7c3aed',
    costs: { low: 0.006, medium: 0.053, high: 0.211 },
  },
};
}

